import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.D5wUhsuj.js";const k=JSON.parse('{"title":"Multi-PHP & WooCommerce Cache","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/multi-php-woocommerce-cache.md","filePath":"tutorials/multi-php-woocommerce-cache.md"}'),t={name:"tutorials/multi-php-woocommerce-cache.md"};function l(h,s,p,r,o,c){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="multi-php-woocommerce-cache" tabindex="-1">Multi-PHP &amp; WooCommerce Cache <a class="header-anchor" href="#multi-php-woocommerce-cache" aria-label="Permalink to &quot;Multi-PHP &amp; WooCommerce Cache&quot;">​</a></h1><p>Two related scenarios that come up together often enough to cover in one place: running several PHP versions side-by-side on one box, and getting FastCGI Cache right on a WooCommerce store (where getting it wrong shows up as &quot;customers seeing each other&#39;s carts,&quot; which is exactly as bad as it sounds — though see below for why AidiPanel&#39;s default rules already prevent this).</p><h2 id="running-multiple-php-versions-on-one-server" tabindex="-1">Running multiple PHP versions on one server <a class="header-anchor" href="#running-multiple-php-versions-on-one-server" aria-label="Permalink to &quot;Running multiple PHP versions on one server&quot;">​</a></h2><p>A common real scenario: you host a legacy client site that&#39;s stuck on PHP 7.4-era code next to a fresh WordPress build you want on 8.4. AidiPanel handles this natively, since <strong>every site already gets its own PHP-FPM pool</strong> — there&#39;s no shared-pool mode to work around.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># See what&#39;s installed vs. just available</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install the version the legacy site needs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Point each site at its own version independently</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> legacy-client.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new-build.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>That&#39;s genuinely the whole procedure — there&#39;s no extra step to &quot;isolate&quot; them from each other since the isolation already exists by default. Each site&#39;s Nginx vhost points <code>fastcgi_pass</code> at that site&#39;s own versioned socket (<code>php8.2-fpm-legacyclient.sock</code> vs. <code>php8.4-fpm-newbuild.sock</code>), so restarting one version&#39;s FPM service, or that specific site&#39;s pool, never touches the other.</p><div class="tip custom-block"><p class="custom-block-title">Testing a PHP upgrade safely</p><p>Before switching a live site&#39;s PHP version, install the target version and test with a temporary subdomain or staging copy first if the codebase is old or uses third-party plugins — see <a href="/docs/guide/php#setting-a-sites-php-version">PHP Management</a> for the switch command, and check <code>storage/logs</code> or the site&#39;s error log immediately after switching either way.</p></div><h2 id="fastcgi-cache-on-woocommerce" tabindex="-1">FastCGI Cache on WooCommerce <a class="header-anchor" href="#fastcgi-cache-on-woocommerce" aria-label="Permalink to &quot;FastCGI Cache on WooCommerce&quot;">​</a></h2><p>WooCommerce is more cache-sensitive than a plain WordPress blog because it mixes genuinely static content (product pages, category listings) with per-visitor dynamic content (cart contents, &quot;you&#39;re logged in,&quot; personalized pricing) on the <em>same URLs</em>. Caching the wrong response to the wrong visitor is the classic WooCommerce caching failure mode — but it&#39;s worth understanding exactly how AidiPanel avoids it before you flip the switch.</p><h3 id="why-this-is-safe-by-default" tabindex="-1">Why this is safe by default <a class="header-anchor" href="#why-this-is-safe-by-default" aria-label="Permalink to &quot;Why this is safe by default&quot;">​</a></h3><p>AidiPanel&#39;s cache exclusion rules (<a href="/docs/guide/fastcgi-cache#what-never-gets-cached">FastCGI Cache → What never gets cached</a>) already bypass caching for:</p><ul><li>any request carrying a <code>woocommerce_items_in_cart</code> cookie</li><li>any request carrying a <code>wordpress_logged_in_*</code> cookie (i.e., any logged-in visitor, including logged-in customers)</li><li>the cart, checkout, and my-account URLs specifically</li><li>any request with a query string, and all <code>POST</code> requests</li></ul><p>In practice this means: <strong>a page only gets cached and served from cache to fully anonymous, cart-empty visitors.</strong> The moment someone adds something to their cart, WooCommerce sets that cookie, and every subsequent request from them bypasses cache automatically — they always see their own live cart, never a cached snapshot of someone else&#39;s.</p><h3 id="turning-it-on" tabindex="-1">Turning it on <a class="header-anchor" href="#turning-it-on" aria-label="Permalink to &quot;Turning it on&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shop.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-nginx-helper</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-redis-plugin</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Both helper flags matter more here than on a plain blog:</p><ul><li><strong><code>--install-nginx-helper</code></strong> — purges cache automatically when product content changes (price edits, stock updates, new posts)</li><li><strong><code>--install-redis-plugin</code></strong> — WooCommerce runs many more database queries per pageview than plain WordPress (cart totals, stock checks, related products); Redis object caching speeds up exactly the requests that FastCGI Cache <em>can&#39;t</em> help with, since logged-in/cart-bearing traffic always bypasses the page cache</li></ul><h3 id="what-to-verify-after-enabling" tabindex="-1">What to verify after enabling <a class="header-anchor" href="#what-to-verify-after-enabling" aria-label="Permalink to &quot;What to verify after enabling&quot;">​</a></h3><p>Don&#39;t just trust the config — check it, especially the first time:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Anonymous visit to a product page — should be cacheable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://shop.example.com/product/example-product/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># X-FastCGI-Cache: MISS (first time), then HIT on a second request</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. Simulate a logged-in visitor — should ALWAYS bypass</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sI</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;wordpress_logged_in_test=1&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://shop.example.com/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> X-FastCGI-Cache</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># X-FastCGI-Cache: BYPASS</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Cart and checkout should always bypass regardless of cookies</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://shop.example.com/cart/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://shop.example.com/checkout/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Both: X-FastCGI-Cache: BYPASS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>If step 2 or 3 ever shows <code>HIT</code> instead of <code>BYPASS</code>, stop and don&#39;t leave cache enabled — that would mean a logged-in or cart-bearing response could theoretically be served to someone else. This shouldn&#39;t happen with AidiPanel&#39;s default rules, but it&#39;s exactly the kind of thing worth confirming yourself rather than assuming, since it&#39;s the one WooCommerce-caching mistake serious enough to matter. If you ever see this, disable cache immediately (<code>aidipanel cache:disable --domain shop.example.com</code>) and treat it as a bug to report.</p><h3 id="excluding-additional-dynamic-pages" tabindex="-1">Excluding additional dynamic pages <a class="header-anchor" href="#excluding-additional-dynamic-pages" aria-label="Permalink to &quot;Excluding additional dynamic pages&quot;">​</a></h3><p>If you use plugins that add their own dynamic, per-user pages outside the standard cart/checkout/account paths (a wishlist plugin, a custom &quot;my orders&quot; page, a membership portal), those need their own bypass rule — they won&#39;t be caught by the default WooCommerce cookie patterns unless they also set one of the cookies above.</p><p>Add a rule to the site&#39;s Nginx config (via the panel&#39;s editor, which validates and rolls back automatically — see <a href="/docs/guide/sites#editing-nginx-config">Site Management → Editing Nginx config</a>):</p><div class="language-nginx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ($request_uri </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~* </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;(/wishlist|/my-orders|/member-portal)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    set </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$skip_cache </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="cache-duration-for-a-store" tabindex="-1">Cache duration for a store <a class="header-anchor" href="#cache-duration-for-a-store" aria-label="Permalink to &quot;Cache duration for a store&quot;">​</a></h3><p>Product pages change less often than you&#39;d think (mostly stock/price), while the homepage or category listings might be closer to real-time if you run flash sales. Consider a shorter TTL than the WordPress default of 1 hour if pricing changes frequently:</p><div class="language-nginx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example: 15 minutes instead of the default 1 hour</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fastcgi_cache_valid </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 301</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 302</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 15m</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>See <a href="/docs/guide/fastcgi-cache#adjusting-cache-duration">FastCGI Cache → Adjusting cache duration</a> for where this line lives and how to reload after editing.</p><h2 id="putting-it-together" tabindex="-1">Putting it together <a class="header-anchor" href="#putting-it-together" aria-label="Permalink to &quot;Putting it together&quot;">​</a></h2><p>A realistic setup for a store running alongside an older site:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Legacy site stays on its known-good PHP version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> legacy-client.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Store gets a modern PHP version plus full caching stack</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shop.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shop.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-nginx-helper</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-redis-plugin</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If the store gets busy enough that its cache is evicting fast, give it headroom</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:zone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --action</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shop.example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 64m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5g</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Each of these is independent per site — none of it requires touching or restarting anything on the neighboring site.</p>`,33)])])}const g=a(t,[["render",l]]);export{k as __pageData,g as default};
